&lt;ul&gt;
&lt;li&gt;&lt;span data-ccp-props=&quot;{&amp;quot;335559737&amp;quot;:-20}&quot;&gt;&lt;span data-teams=&quot;true&quot;&gt;&lt;strong&gt;Threat and risk assessment:&lt;/strong&gt; Continuously evaluating potential threats and vulnerabilities to develop mitigation strategies.&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span data-ccp-props=&quot;{&amp;quot;335559737&amp;quot;:-20}&quot;&gt;&lt;span data-teams=&quot;true&quot;&gt;&lt;strong&gt;Advance planning:&lt;/strong&gt; Conducting reconnaissance of locations, planning secure travel routes, and preparing emergency plans before the client arrives.&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span data-ccp-props=&quot;{&amp;quot;335559737&amp;quot;:-20}&quot;&gt;&lt;span data-teams=&quot;true&quot;&gt;&lt;strong&gt;Close protection:&lt;/strong&gt; Providing a physical security presence and immediate defense for the client during travel and events.&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span data-ccp-props=&quot;{&amp;quot;335559737&amp;quot;:-20}&quot;&gt;&lt;span data-teams=&quot;true&quot;&gt;&lt;strong&gt;Crisis management:&lt;/strong&gt; Making rapid, decisive actions during emergencies, including medical incidents, security breaches, or hostile situations.&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span data-ccp-props=&quot;{&amp;quot;335559737&amp;quot;:-20}&quot;&gt;&lt;span data-teams=&quot;true&quot;&gt;&lt;strong&gt;Secure transportation:&lt;/strong&gt; Arranging and providing secure transport, which includes defensive and evasive driving&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span data-ccp-props=&quot;{&amp;quot;335559737&amp;quot;:-20}&quot;&gt;&lt;span data-teams=&quot;true&quot;&gt;&lt;strong&gt;Liaison:&lt;/strong&gt; Coordinating with law enforcement, local authorities, and venue staff to ensure a seamless and secure operation.&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span data-ccp-props=&quot;{&amp;quot;335559737&amp;quot;:-20}&quot;&gt;&lt;span data-teams=&quot;true&quot;&gt;&lt;strong&gt;Surveillance:&lt;/strong&gt; Performing surveillance detection and counter-surveillance to identify and deter threats.&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span style=&quot;font-family: helvetica, arial, sans-serif;&quot;&gt;&lt;strong&gt;Residential protection:&lt;/strong&gt; Monitor the property through command center technology, screening visitors and vendors, and controlling all access points to the protected site.&lt;/span&gt;&lt;/li&gt;
